import { z } from 'zod';

// Define the shape of the environment variables
const envSchema = z.object({
  MONGO_URI: z.string().url(),
  JWT_SECRET: z.string().min(32), // JWT Secret should be at least 32 characters
  TELEGRAM_TOKEN: z.string(),
  RATE_LIMIT_MAX: z.preprocess((val) => parseInt(val as string, 10), z.number().min(1)),
  RATE_LIMIT_WINDOW: z.preprocess((val) => parseInt(val as string, 10), z.number().min(1)),
});

// Validating the environment variables
const _env = envSchema.safeParse(process.env);

if (!_env.success) {
  // If validation fails, output the error to the console and exit the process
  console.error('❌ Invalid environment variables:', _env.error.format());
  process.exit(1);
}

export const env = _env.data;
